'use client'
import { useState } from 'react'
import { useRouter } from 'next/navigation'
import { motion } from 'framer-motion'
import { useAuthStore } from '@/store/useAuthStore'
import { 
  UserIcon, 
  KeyIcon,
  BuildingStorefrontIcon,
  UserCircleIcon,
  ArrowRightIcon 
} from '@heroicons/react/24/outline'

export default function LoginPage() {
  const router = useRouter()
  const { setUser } = useAuthStore()
  const [isLoading, setIsLoading] = useState(false)

  const handleDemoLogin = (role: 'admin' | 'staff') => {
    setIsLoading(true)
    
    // Simulate login delay
    setTimeout(() => {
      const demoUser = {
        id: role === 'admin' ? 'admin-001' : 'staff-001',
        name: role === 'admin' ? 'Admin User' : 'Staff User',
        email: role === 'admin' ? 'admin@brancha.com' : 'staff@brancha.com',
        role: role,
        tenantId: 'branch-a'
      }
      
      setUser(demoUser)
      router.push('/')
    }, 1000)
  }

  return (
    <div className="min-h-screen bg-linear-to-br from-slate-900 via-blue-900 to-slate-900 flex items-center justify-center p-4">
      {/* Background Pattern */}
      <div className="absolute inset-0 overflow-hidden">
        <div className="absolute -top-40 -right-40 w-80 h-80 bg-blue-500/10 rounded-full blur-3xl"></div>
        <div className="absolute -bottom-40 -left-40 w-80 h-80 bg-purple-500/10 rounded-full blur-3xl"></div>
      </div>

      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.6 }}
        className="relative z-10 w-full max-w-md"
      >
        {/* Logo/Header */}
        <div className="text-center mb-8">
          <motion.div
            initial={{ scale: 0.8 }}
            animate={{ scale: 1 }}
            transition={{ delay: 0.2, duration: 0.4 }}
            className="inline-flex items-center justify-center w-16 h-16 bg-white/10 backdrop-blur-sm rounded-2xl mb-4 ring-1 ring-white/20"
          >
            <BuildingStorefrontIcon className="w-8 h-8 text-white" />
          </motion.div>
          <h1 className="text-3xl font-bold text-white mb-2">POS System</h1>
          <p className="text-white/70">Professional Point of Sale Management</p>
        </div>

        {/* Login Card */}
        <motion.div
          initial={{ opacity: 0, scale: 0.95 }}
          animate={{ opacity: 1, scale: 1 }}
          transition={{ delay: 0.3, duration: 0.4 }}
          className="bg-white/10 backdrop-blur-xl rounded-2xl p-8 ring-1 ring-white/20 shadow-2xl"
        >
          <div className="text-center mb-6">
            <h2 className="text-xl font-semibold text-white mb-2">Welcome Back</h2>
            <p className="text-white/60 text-sm">Choose your demo role to continue</p>
          </div>

          {/* Demo Login Buttons */}
          <div className="space-y-4">
            {/* Admin Login */}
            <motion.button
              whileHover={{ scale: 1.02 }}
              whileTap={{ scale: 0.98 }}
              onClick={() => handleDemoLogin('admin')}
              disabled={isLoading}
              className="w-full p-4 bg-linear-to-r from-blue-600/80 to-blue-700/80 hover:from-blue-600 hover:to-blue-700 rounded-xl text-white font-medium transition-all duration-200 backdrop-blur-sm border border-white/20 shadow-lg hover:shadow-xl flex items-center justify-center gap-3"
            >
              <UserCircleIcon className="w-5 h-5" />
              <span>Login as Admin (Branch A)</span>
              <ArrowRightIcon className="w-4 h-4" />
            </motion.button>

            {/* Staff Login */}
            <motion.button
              whileHover={{ scale: 1.02 }}
              whileTap={{ scale: 0.98 }}
              onClick={() => handleDemoLogin('staff')}
              disabled={isLoading}
              className="w-full p-4 bg-linear-to-r from-emerald-600/80 to-emerald-700/80 hover:from-emerald-600 hover:to-emerald-700 rounded-xl text-white font-medium transition-all duration-200 backdrop-blur-sm border border-white/20 shadow-lg hover:shadow-xl flex items-center justify-center gap-3"
            >
              <UserIcon className="w-5 h-5" />
              <span>Login as Staff (Branch A)</span>
              <ArrowRightIcon className="w-4 h-4" />
            </motion.button>
          </div>

          {/* Loading State */}
          {isLoading && (
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              className="mt-4 p-3 bg-white/10 rounded-lg text-center"
            >
              <div className="inline-flex items-center gap-2 text-white/80">
                <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                <span className="text-sm">Authenticating...</span>
              </div>
            </motion.div>
          )}

          {/* Features/Info */}
          <div className="mt-8 pt-6 border-t border-white/10">
            <div className="grid grid-cols-2 gap-4 text-center">
              <div>
                <div className="text-white/60 text-xs">Role</div>
                <div className="text-white font-medium">Demo Access</div>
              </div>
              <div>
                <div className="text-white/60 text-xs">Branch</div>
                <div className="text-white font-medium">Branch A</div>
              </div>
            </div>
          </div>
        </motion.div>

        {/* Footer */}
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ delay: 0.8 }}
          className="text-center mt-6"
        >
          <p className="text-white/50 text-sm">
            Professional POS System with Multi-tenant Support
          </p>
        </motion.div>
      </motion.div>
    </div>
  )
}